import{_ as t,o as a,c as n,a2 as s}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Benchmarks and Evaluation","description":"","frontmatter":{},"headers":[],"relativePath":"research/concepts/agentic-loop/benchmarks-and-evaluation.md","filePath":"research/concepts/agentic-loop/benchmarks-and-evaluation.md"}'),o={name:"research/concepts/agentic-loop/benchmarks-and-evaluation.md"};function i(r,e,l,d,c,h){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="benchmarks-and-evaluation" tabindex="-1">Benchmarks and Evaluation <a class="header-anchor" href="#benchmarks-and-evaluation" aria-label="Permalink to &quot;Benchmarks and Evaluation&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Benchmarks drive agent development — what gets measured gets optimized. The coding agent benchmark landscape has evolved rapidly since 2023, growing from simple function-completion tasks (HumanEval) to full end-to-end issue-resolution harnesses (SWE-bench) that exercise every layer of an agentic loop: issue comprehension, codebase navigation, multi-file editing, tool orchestration, and verification.</p><p>Different benchmarks test fundamentally different aspects of the loop. A benchmark that evaluates single-function generation (HumanEval) tells you about model quality; one that evaluates full GitHub-issue resolution (SWE-bench) tells you about agent architecture. How you benchmark shapes which loop components you invest in: if your target metric is SWE-bench Verified, you will build verification loops and file-search tools; if your target is Terminal-Bench, you will invest in shell error recovery and state tracking.</p><p>The most important meta-insight from the benchmark landscape is that simple loops can compete with complex ones when the underlying model is strong enough. mini-SWE-agent — 100 lines of Python — scores 65 % on SWE-bench Verified. This does not mean loop design is irrelevant; it means that the marginal value of loop complexity must be evaluated against the marginal value of a better model.</p><hr><h2 id="swe-bench-—-the-gold-standard" tabindex="-1">SWE-bench — The Gold Standard <a class="header-anchor" href="#swe-bench-—-the-gold-standard" aria-label="Permalink to &quot;SWE-bench — The Gold Standard&quot;">​</a></h2><p>SWE-bench (Software Engineering Benchmark) was introduced by Jimenez et al. in late 2023 and quickly became the most-cited evaluation for coding agents. It converts real GitHub issues and their corresponding pull-request fixes into a reproducible test harness.</p><h3 id="variants" tabindex="-1">Variants <a class="header-anchor" href="#variants" aria-label="Permalink to &quot;Variants&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Variant</th><th>Tasks</th><th>Description</th></tr></thead><tbody><tr><td><strong>SWE-bench Full</strong></td><td>2,294</td><td>Real GitHub issues from 12 Python repositories</td></tr><tr><td><strong>SWE-bench Verified</strong></td><td>500</td><td>Human-vetted subset; the most-cited leaderboard</td></tr><tr><td><strong>SWE-bench Lite</strong></td><td>300</td><td>Curated subset for cheaper evaluation runs</td></tr><tr><td><strong>SWE-bench Multilingual</strong></td><td>300</td><td>Tasks across 9 programming languages (Java, JS, Go, Rust, …)</td></tr><tr><td><strong>SWE-bench Multimodal</strong></td><td>517</td><td>Issues containing visual elements — screenshots, UI diagrams, plots</td></tr></tbody></table><p><strong>SWE-bench Full</strong> draws from repositories like Django, Flask, Scikit-learn, Sympy, Matplotlib, Astropy, Requests, Sphinx, Pylint, Pytest, xarray, and Seaborn. Each task consists of:</p><ol><li>A natural-language issue description (often including stack traces, reproduction steps).</li><li>A repository snapshot checked out to a specific commit.</li><li>A test suite that the agent&#39;s patch must pass (including both the new regression test from the PR and all pre-existing tests).</li></ol><p><strong>SWE-bench Verified</strong> was created because the original full set contains ambiguous or under-specified issues. Human annotators reviewed each task to confirm it is solvable given only the information in the issue description and the repository state. This makes Verified the fairest comparison point across agents.</p><p><strong>SWE-bench Multilingual</strong> extends evaluation beyond Python. This matters because many loop components — file search heuristics, test-runner invocations, language-specific linting — must generalize across ecosystems. An agent that hard-codes <code>pytest</code> as its test runner will fail on Java tasks.</p><p><strong>SWE-bench Multimodal</strong> adds an important dimension: many real issues include screenshots (&quot;the button renders wrong&quot;), plots (&quot;the axis labels overlap&quot;), or diagrams. Agents that can only process text will miss these. This variant pushes loop design toward vision-capable models or image-description pre-processing steps.</p><h3 id="what-it-tests" tabindex="-1">What It Tests <a class="header-anchor" href="#what-it-tests" aria-label="Permalink to &quot;What It Tests&quot;">​</a></h3><p>SWE-bench exercises the <strong>full agentic loop</strong>:</p><ol><li><strong>Issue comprehension</strong> — parse a natural-language description, sometimes with stack traces, code snippets, or references to specific files.</li><li><strong>Codebase navigation</strong> — find the relevant files in a repository with hundreds or thousands of files. Agents must decide what to search for, read, and ignore.</li><li><strong>Patch generation</strong> — produce a diff that fixes the issue without breaking existing functionality.</li><li><strong>Verification</strong> — the generated patch is applied and the full test suite is run. Only patches that pass <em>all</em> tests (existing + the PR&#39;s new test) count as resolved.</li></ol><p>This end-to-end nature is what makes SWE-bench the gold standard. A model that can generate perfect isolated functions (HumanEval 100 %) may still fail SWE-bench because it cannot <em>find</em> the right file to edit, or because its edit breaks an import in a downstream module.</p><h3 id="scoring" tabindex="-1">Scoring <a class="header-anchor" href="#scoring" aria-label="Permalink to &quot;Scoring&quot;">​</a></h3><ul><li><strong>% Resolved</strong>: the percentage of instances where the agent&#39;s patch passes all tests.</li><li>Current state-of-the-art on <strong>SWE-bench Verified</strong>: approximately <strong>74 %</strong> (mid-2025).</li><li>On the <strong>Full</strong> set, scores are lower (typically 30–50 %) because it includes ambiguous or extremely difficult tasks.</li><li>Cost matters: some agents spend $2–5 per task; at 500 tasks, a single evaluation run on Verified can cost $1,000–$2,500 in API calls.</li></ul><h3 id="how-swe-bench-drives-loop-design" tabindex="-1">How SWE-bench Drives Loop Design <a class="header-anchor" href="#how-swe-bench-drives-loop-design" aria-label="Permalink to &quot;How SWE-bench Drives Loop Design&quot;">​</a></h3><p>SWE-bench has directly shaped the tool sets and loop architectures of every major coding agent:</p><p><strong>Minimum tool set.</strong> To solve SWE-bench tasks, an agent needs at minimum:</p><ul><li><code>search</code> (grep, ripgrep, or semantic search across the repo)</li><li><code>read</code> (view file contents, possibly with line ranges)</li><li><code>edit</code> (apply a patch, replace lines, or insert code)</li><li><code>bash</code> (run tests, install dependencies, inspect runtime behavior)</li></ul><p>Every major agent (SWE-agent, OpenHands, Aider, Devon, Cursor Agent) implements some variant of this quartet. SWE-bench made this the de facto standard.</p><p><strong>Long context.</strong> Some issues require understanding 10+ files simultaneously. Agents with larger context windows or effective summarization score higher on these tasks. This drove investment in context compaction (dropping older messages, summarizing tool outputs).</p><p><strong>Verification loops.</strong> Because scoring is binary (pass all tests or fail), agents that run tests after each edit attempt can catch regressions before submitting. The build-test-fix cycle that many agents implement was directly motivated by SWE-bench scoring.</p><p><strong>Edit format precision.</strong> Malformed patches (wrong line numbers, incorrect indentation, partial edits) cause test failures even when the logic is correct. This drove SWE-agent&#39;s <code>edit</code> command design and Aider&#39;s multiple edit-format experiments.</p><h3 id="key-insight-mini-swe-agent" tabindex="-1">Key Insight: mini-SWE-agent <a class="header-anchor" href="#key-insight-mini-swe-agent" aria-label="Permalink to &quot;Key Insight: mini-SWE-agent&quot;">​</a></h3><p>In early 2025, researchers demonstrated that a minimal agent — <strong>100 lines of Python</strong> — could score <strong>65 % on SWE-bench Verified</strong>. This agent, dubbed mini-SWE-agent, uses the simplest possible loop:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>while not done:</span></span>
<span class="line"><span>    response = model.query(context)</span></span>
<span class="line"><span>    result = execute(response.tool_call)</span></span>
<span class="line"><span>    context.append(result)</span></span></code></pre></div><p>No planning phase. No reflection step. No multi-agent delegation. No sophisticated context management. Just query → execute → append → repeat.</p><p>This result is profoundly important for loop design. It suggests that <strong>model quality is the dominant variable</strong>, and that loop complexity has diminishing returns once you have a strong model and a functional tool set. It does <em>not</em> mean complex loops are useless — they help on harder tasks, reduce cost on easy tasks, and improve reliability — but it reframes the question: <em>how much additional % does each loop component add, and at what cost?</em></p><p>The &quot;roulette&quot; experiment reinforces this: randomly switching between models mid-task can actually <em>improve</em> aggregate benchmark scores, because different models have complementary strengths. This suggests that model diversity may matter more than loop sophistication.</p><hr><h2 id="terminal-bench" tabindex="-1">Terminal-Bench <a class="header-anchor" href="#terminal-bench" aria-label="Permalink to &quot;Terminal-Bench&quot;">​</a></h2><p>Terminal-Bench evaluates agents on CLI and system-administration tasks — a complementary angle to SWE-bench&#39;s focus on code editing.</p><h3 id="versions" tabindex="-1">Versions <a class="header-anchor" href="#versions" aria-label="Permalink to &quot;Versions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Version</th><th>Tasks</th><th>Focus</th></tr></thead><tbody><tr><td><strong>Terminal-Bench 1.0</strong></td><td>~50</td><td>Initial release; basic CLI tasks</td></tr><tr><td><strong>Terminal-Bench 2.0</strong></td><td>89</td><td>Realistic CLI environments; expanded scope</td></tr><tr><td><strong>Terminal-Bench 3.0</strong></td><td>100+</td><td>Further expanded; multi-step system tasks</td></tr></tbody></table><h3 id="what-it-tests-1" tabindex="-1">What It Tests <a class="header-anchor" href="#what-it-tests-1" aria-label="Permalink to &quot;What It Tests&quot;">​</a></h3><ul><li><strong>File system navigation</strong>: finding files, parsing directory structures, manipulating paths.</li><li><strong>System administration</strong>: managing processes, configuring services, editing config files.</li><li><strong>Multi-step command sequences</strong>: tasks that require 5–20 sequential shell commands, each depending on the output of the previous one.</li><li><strong>Error recovery</strong>: commands fail frequently in terminal environments (wrong flags, missing packages, permission issues). Agents must detect failures and retry with corrections.</li><li><strong>Non-interactive execution</strong>: many CLI tools prompt for input (<code>y/n</code>, interactive editors). Agents must handle these or invoke tools with non-interactive flags.</li></ul><h3 id="how-it-drives-loop-design" tabindex="-1">How It Drives Loop Design <a class="header-anchor" href="#how-it-drives-loop-design" aria-label="Permalink to &quot;How It Drives Loop Design&quot;">​</a></h3><p>Terminal-Bench exposes weaknesses that SWE-bench does not. An agent might be excellent at editing Python files but terrible at running shell commands reliably. Key design pressures:</p><p><strong>Reliable shell execution.</strong> Agents must correctly invoke commands, capture stdout/stderr, detect exit codes, and handle timeouts. This pushes loop implementations toward robust <code>bash</code> tool implementations with proper error reporting.</p><p><strong>Error recovery is critical.</strong> In Terminal-Bench, commands fail at a much higher rate than in typical SWE-bench tasks (wrong flags, missing dependencies, unexpected output formats). Agents with explicit retry logic or error-classification steps score significantly higher.</p><p><strong>State tracking across commands.</strong> Unlike SWE-bench (where the codebase is mostly static between edits), Terminal-Bench tasks modify system state. The agent must track what it has already done — what files it created, what services it started, what environment variables it set — to avoid undoing its own progress.</p><p><strong>ForgeCode&#39;s progression on Terminal-Bench</strong> illustrates how benchmark results drive loop improvements:</p><ul><li>Initial score: ~25 % (basic agent loop)</li><li>After adding verification enforcement: ~30 %</li><li>After tool-call correction (auto-fixing malformed commands): ~35 %</li><li>After non-interactive mode optimization: ~38 %</li></ul><p>Each improvement was directly motivated by failure analysis on Terminal-Bench tasks.</p><h3 id="notable-results" tabindex="-1">Notable Results <a class="header-anchor" href="#notable-results" aria-label="Permalink to &quot;Notable Results&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Terminal-Bench 2.0 Score</th><th>Key Feature</th></tr></thead><tbody><tr><td>TongAgents</td><td>80.2 %</td><td>Multi-agent collaboration</td></tr><tr><td>ForgeCode (latest)</td><td>~38 %</td><td>Verification + tool correction</td></tr><tr><td>Baseline GPT-4</td><td>~20 %</td><td>No agentic loop</td></tr></tbody></table><p>The gap between TongAgents (80.2 %) and a bare model (20 %) demonstrates that <strong>loop design matters enormously for terminal tasks</strong>, even more so than for code editing tasks. Multi-agent architectures — where one agent plans and another executes — show particular strength here.</p><hr><h2 id="humaneval-and-mbpp" tabindex="-1">HumanEval and MBPP <a class="header-anchor" href="#humaneval-and-mbpp" aria-label="Permalink to &quot;HumanEval and MBPP&quot;">​</a></h2><p>These older benchmarks predate the agentic era but remain important as baselines for model capability.</p><h3 id="humaneval" tabindex="-1">HumanEval <a class="header-anchor" href="#humaneval" aria-label="Permalink to &quot;HumanEval&quot;">​</a></h3><ul><li><strong>164</strong> Python function-completion problems.</li><li>Each problem includes a function signature, docstring, and a set of unit tests.</li><li>The agent (or model) must generate the function body.</li><li>Metric: <strong>pass@k</strong> — the probability that at least one of k generated samples passes all tests. Typically reported as pass@1 (single attempt).</li><li>Current frontier models score 95–99 % on pass@1.</li></ul><p>HumanEval does <strong>not</strong> test the agentic loop. There is no codebase to navigate, no issue to parse, no multi-file context. It tests raw code generation quality.</p><h3 id="mbpp-mostly-basic-programming-problems" tabindex="-1">MBPP (Mostly Basic Programming Problems) <a class="header-anchor" href="#mbpp-mostly-basic-programming-problems" aria-label="Permalink to &quot;MBPP (Mostly Basic Programming Problems)&quot;">​</a></h3><ul><li><strong>974</strong> Python programming problems drawn from crowd-sourced descriptions.</li><li>Broader coverage than HumanEval but individually simpler.</li><li>Same pass@k metric.</li><li>Current frontier models score 90–95 %.</li></ul><h3 id="why-these-matter-for-agents" tabindex="-1">Why These Matter for Agents <a class="header-anchor" href="#why-these-matter-for-agents" aria-label="Permalink to &quot;Why These Matter for Agents&quot;">​</a></h3><p>HumanEval and MBPP measure the <strong>model quality component</strong> of agent performance. An agent&#39;s ability to solve SWE-bench tasks decomposes (roughly) into:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>agent_performance ≈ f(model_quality, loop_design, tool_quality)</span></span></code></pre></div><p>HumanEval/MBPP measure <code>model_quality</code> in isolation. A model that scores 60 % on HumanEval will produce worse patches in an agentic loop than a model scoring 95 %, all else equal. But the relationship is not linear — loop design and tool quality create multiplicative effects. A mediocre model in an excellent loop can outperform an excellent model with no loop (this is exactly what SWE-bench demonstrates).</p><p><strong>The orthogonality insight</strong>: model quality and loop quality are largely independent axes. You can improve either one. The benchmark ecosystem helps you isolate which axis to invest in:</p><ul><li>Low HumanEval score + low SWE-bench score → improve the model first.</li><li>High HumanEval score + low SWE-bench score → improve the loop / tools.</li><li>High HumanEval score + high SWE-bench score → optimize cost, latency, UX.</li></ul><hr><h2 id="agentbench" tabindex="-1">AgentBench <a class="header-anchor" href="#agentbench" aria-label="Permalink to &quot;AgentBench&quot;">​</a></h2><h3 id="overview-1" tabindex="-1">Overview <a class="header-anchor" href="#overview-1" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>AgentBench (Liu et al., 2023, Tsinghua University) was the first systematic benchmark to evaluate LLMs as agents across multiple interactive environments. It tests whether a model can <em>act</em> in the world, not just generate text.</p><h3 id="environments" tabindex="-1">Environments <a class="header-anchor" href="#environments" aria-label="Permalink to &quot;Environments&quot;">​</a></h3><table tabindex="0"><thead><tr><th>#</th><th>Environment</th><th>Description</th></tr></thead><tbody><tr><td>1</td><td><strong>Operating System</strong></td><td>Execute shell commands, navigate file systems, manage processes</td></tr><tr><td>2</td><td><strong>Database</strong></td><td>Write SQL queries, manage schemas, interpret query results</td></tr><tr><td>3</td><td><strong>Knowledge Graph</strong></td><td>Navigate entity relationships, answer multi-hop questions</td></tr><tr><td>4</td><td><strong>Web Browsing</strong></td><td>Interact with web pages, fill forms, click links</td></tr><tr><td>5</td><td><strong>Lateral Thinking</strong></td><td>Solve creative reasoning puzzles via interaction</td></tr><tr><td>6</td><td><strong>House Holding</strong></td><td>Navigate simulated household environments (ALFWorld)</td></tr><tr><td>7</td><td><strong>Digital Card Game</strong></td><td>Play card games requiring strategy</td></tr><tr><td>8</td><td><strong>Web Shopping</strong></td><td>Find and purchase items on simulated e-commerce sites</td></tr></tbody></table><h3 id="relevance-for-coding-agents" tabindex="-1">Relevance for Coding Agents <a class="header-anchor" href="#relevance-for-coding-agents" aria-label="Permalink to &quot;Relevance for Coding Agents&quot;">​</a></h3><p>The OS and Database environments directly test capabilities that coding agents need:</p><ul><li>Executing shell commands reliably (same as Terminal-Bench).</li><li>Writing and debugging SQL (relevant for data-engineering agents).</li><li>Managing file systems and processes.</li></ul><p>The Web Browsing environment is relevant for agents that need to read documentation, search Stack Overflow, or interact with web-based tools (CI dashboards, issue trackers).</p><p>AgentBench&#39;s key contribution is demonstrating that agent capability varies enormously across environments. A model might excel at OS tasks but fail at web browsing. This implies that <strong>loop design should be environment-aware</strong> — the same loop structure may not work equally well for terminal tasks and web tasks.</p><h3 id="results-summary" tabindex="-1">Results Summary <a class="header-anchor" href="#results-summary" aria-label="Permalink to &quot;Results Summary&quot;">​</a></h3><p>In the original paper, GPT-4 significantly outperformed all other models across environments. Open-source models (LLaMA, Vicuna) struggled, particularly on tasks requiring multi-step reasoning. This was an early signal that <strong>model scale matters for agentic tasks</strong>, and that fine-tuning on agent trajectories could help close the gap.</p><hr><h2 id="codeclash-newer" tabindex="-1">CodeClash (Newer) <a class="header-anchor" href="#codeclash-newer" aria-label="Permalink to &quot;CodeClash (Newer)&quot;">​</a></h2><p>CodeClash was announced in late 2025 by members of the SWE-bench team and represents a philosophical shift in agent evaluation.</p><ul><li><strong>Goal-oriented, not task-oriented</strong>: instead of &quot;fix this issue,&quot; CodeClash defines higher-level goals (&quot;improve the test coverage of this module,&quot; &quot;refactor this subsystem to use the new API&quot;) and evaluates whether the agent makes meaningful progress.</li><li><strong>Open-ended evaluation</strong>: there is no single correct patch. Multiple approaches may be valid. Evaluation uses a combination of automated checks and human review.</li><li><strong>More realistic</strong>: real development work is rarely as well-specified as a GitHub issue with a failing test. CodeClash aims to test agent behavior under ambiguity.</li><li><strong>Website</strong>: <a href="https://codeclash.ai" target="_blank" rel="noreferrer">https://codeclash.ai</a></li></ul><p>CodeClash is still maturing, but it signals where the benchmark community is heading: toward evaluations that test judgment, planning, and iterative refinement — the higher-order capabilities that separate good agents from great ones.</p><hr><h2 id="aider-s-code-editing-benchmark" tabindex="-1">Aider&#39;s Code Editing Benchmark <a class="header-anchor" href="#aider-s-code-editing-benchmark" aria-label="Permalink to &quot;Aider&#39;s Code Editing Benchmark&quot;">​</a></h2><h3 id="structure" tabindex="-1">Structure <a class="header-anchor" href="#structure" aria-label="Permalink to &quot;Structure&quot;">​</a></h3><p>Aider (an open-source AI pair-programming tool) maintains its own benchmark specifically designed to test the <strong>edit-apply-verify</strong> loop:</p><ol><li><strong>133 Exercism Python exercises</strong> serve as the task set.</li><li><strong>Two-attempt evaluation</strong>: <ul><li><strong>Attempt 1</strong>: Send the exercise description + function stub to the LLM. Apply the response as an edit. Run tests.</li><li><strong>If tests fail</strong>: Send the first 50 lines of test errors back to the LLM with a &quot;fix it&quot; instruction. Apply the fix. Run tests again.</li><li><strong>Attempt 2 result</strong>: Record pass/fail.</li></ul></li><li>This directly tests the loop&#39;s ability to <strong>generate an edit</strong>, <strong>apply it correctly</strong> (parse the edit format, produce valid code), and <strong>recover from errors</strong>.</li></ol><h3 id="how-it-drives-design" tabindex="-1">How It Drives Design <a class="header-anchor" href="#how-it-drives-design" aria-label="Permalink to &quot;How It Drives Design&quot;">​</a></h3><p>Aider&#39;s benchmark has been instrumental in developing and comparing <strong>edit formats</strong> — the syntax an LLM uses to express code changes:</p><table tabindex="0"><thead><tr><th>Edit Format</th><th>Description</th><th>Strengths</th></tr></thead><tbody><tr><td><strong>whole</strong></td><td>Return entire file content</td><td>Simple; no parsing errors</td></tr><tr><td><strong>diff</strong></td><td>Unified diff format</td><td>Compact; familiar</td></tr><tr><td><strong>udiff</strong></td><td>Modified unified diff</td><td>Better line-number handling</td></tr><tr><td><strong>search/replace</strong></td><td>Search for old code, replace with new</td><td>Precise; works well with large files</td></tr><tr><td><strong>editor-diff</strong></td><td>Structured diff with editor commands</td><td>Reduced ambiguity</td></tr><tr><td><strong>editor-whole</strong></td><td>Structured whole-file with editor commands</td><td>Combines precision and simplicity</td></tr></tbody></table><p>Different models perform best with different edit formats. For example, Claude models tend to perform well with whole-file and search/replace formats, while GPT models may prefer diff-based formats. This is not a minor detail — <strong>the wrong edit format can cost 10–20 % on the benchmark</strong>.</p><h3 id="leaderboard-insights" tabindex="-1">Leaderboard Insights <a class="header-anchor" href="#leaderboard-insights" aria-label="Permalink to &quot;Leaderboard Insights&quot;">​</a></h3><ul><li><strong>Architect mode</strong> (two-model approach: one model reasons about the change, another generates the edit) often outperforms single-model approaches. This validates the &quot;planner + coder&quot; pattern used by several agent architectures.</li><li>The benchmark has directly led to Aider&#39;s innovations in edit format design, including the search/replace format that has been adopted by other tools.</li><li>Cost per task varies dramatically: from $0.01 (small fast models) to $0.50+ (large frontier models with whole-file output).</li></ul><hr><h2 id="swe-smith" tabindex="-1">SWE-smith <a class="header-anchor" href="#swe-smith" aria-label="Permalink to &quot;SWE-smith&quot;">​</a></h2><p>SWE-smith (released May 2025) is not a benchmark per se but a <strong>training data generation pipeline</strong> for software engineering agents. It is included here because it represents a crucial link between benchmarks and agent improvement:</p><ul><li><strong>Synthetic trajectory generation</strong>: Run existing agents on SWE-bench tasks, collect successful trajectories, and use them as training data.</li><li><strong>Fine-tuning pipeline</strong>: Take an open-source model (e.g., LLaMA, CodeLlama) and fine-tune it on these trajectories to produce a specialized coding-agent model.</li><li><strong>Bootstrapping</strong>: Fine-tuned models can generate new trajectories, which can be used to fine-tune further (iterative self-improvement).</li></ul><p>SWE-smith demonstrates that benchmark performance can be directly translated into training signal. This creates a feedback loop:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>benchmark → evaluate agent → collect trajectories → fine-tune model → better agent → benchmark</span></span></code></pre></div><p>This is the mechanism by which benchmarks <em>literally</em> shape model capabilities, not just measure them.</p><hr><h2 id="how-benchmarks-drive-loop-design-decisions" tabindex="-1">How Benchmarks Drive Loop Design Decisions <a class="header-anchor" href="#how-benchmarks-drive-loop-design-decisions" aria-label="Permalink to &quot;How Benchmarks Drive Loop Design Decisions&quot;">​</a></h2><h3 id="_1-tool-set-design" tabindex="-1">1. Tool Set Design <a class="header-anchor" href="#_1-tool-set-design" aria-label="Permalink to &quot;1. Tool Set Design&quot;">​</a></h3><p>Benchmarks define the <strong>minimum viable tool set</strong> for coding agents:</p><ul><li><strong>SWE-bench requires</strong>: file search, file read, file edit, bash execution.</li><li><strong>Terminal-Bench requires</strong>: reliable shell execution with error detection.</li><li><strong>AgentBench requires</strong>: environment-specific interaction protocols.</li></ul><p>This convergence is why virtually every coding agent implements the same four core tools (search, read, edit, bash) — because that is what you need to score well on SWE-bench. Agents that add more tools (web browsing, image analysis, LSP integration) do so to capture additional benchmark points or to target benchmarks beyond SWE-bench.</p><h3 id="_2-verification-integration" tabindex="-1">2. Verification Integration <a class="header-anchor" href="#_2-verification-integration" aria-label="Permalink to &quot;2. Verification Integration&quot;">​</a></h3><p>SWE-bench&#39;s binary scoring (all tests pass or fail) creates a strong incentive to integrate verification into the loop:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>edit → run tests → if fail: analyze errors → edit again → run tests → …</span></span></code></pre></div><p>Agents without verification loops leave points on the table. Many initial edits have minor errors (off-by-one in line numbers, missing imports, wrong indentation) that a single test run would catch. The verification loop converts these near-misses into successes.</p><p>ForgeCode&#39;s verification enforcement was directly motivated by Terminal-Bench analysis: they found that 30 % of failures could be recovered by running a verification step and retrying.</p><h3 id="_3-context-management" tabindex="-1">3. Context Management <a class="header-anchor" href="#_3-context-management" aria-label="Permalink to &quot;3. Context Management&quot;">​</a></h3><p>Long SWE-bench tasks (complex Django issues, multi-file Scikit-learn refactors) require the agent to hold information from 10–20 files simultaneously. This drives investment in:</p><ul><li><strong>Context compaction</strong>: summarizing older messages to free token budget.</li><li><strong>Sliding windows</strong>: keeping only the most recent N messages.</li><li><strong>Hierarchical context</strong>: maintaining a &quot;scratchpad&quot; of key facts separate from the full conversation history.</li></ul><p>But short tasks (60 % of SWE-bench) do not need any of this. mini-SWE-agent wins without compaction because most tasks fit comfortably within a large model&#39;s context window. The lesson: context management is only valuable for the long tail, but the long tail is where the hardest (and most differentiating) tasks live.</p><h3 id="_4-error-recovery" tabindex="-1">4. Error Recovery <a class="header-anchor" href="#_4-error-recovery" aria-label="Permalink to &quot;4. Error Recovery&quot;">​</a></h3><p>Both SWE-bench and Terminal-Bench involve frequent tool failures:</p><ul><li>Bash commands return non-zero exit codes.</li><li>File edits fail to apply (wrong line numbers, file not found).</li><li>Tests fail with unexpected errors.</li><li>Models generate malformed tool calls.</li></ul><p>Agents with better error recovery consistently score higher. Key patterns:</p><ul><li><strong>Retry with correction</strong>: detect the error, send it back to the model, let it try again.</li><li><strong>Stuck detection</strong>: if the agent has made N attempts without progress, reset or escalate (OpenHands implements this explicitly, motivated by benchmark evaluation).</li><li><strong>Tool-call validation</strong>: catch malformed tool calls before execution and ask the model to reformat (ForgeCode&#39;s tool-call correction).</li></ul><h3 id="_5-simple-vs-complex-loops" tabindex="-1">5. Simple vs Complex Loops <a class="header-anchor" href="#_5-simple-vs-complex-loops" aria-label="Permalink to &quot;5. Simple vs Complex Loops&quot;">​</a></h3><p>The most provocative benchmark result is mini-SWE-agent&#39;s 65 % on SWE-bench Verified with 100 lines of code. Combined with:</p><ul><li>The &quot;roulette&quot; experiment (random model switching improves aggregate scores).</li><li>The observation that model quality correlates more strongly with SWE-bench scores than loop complexity does.</li><li>The diminishing returns of adding loop features (each feature adds 1–3 % but increases cost and latency).</li></ul><p>These results suggest a design principle: <strong>start with the simplest loop that works, add complexity only when benchmarks prove it helps, and always compare against the simple baseline.</strong></p><hr><h2 id="benchmark-comparison-table" tabindex="-1">Benchmark Comparison Table <a class="header-anchor" href="#benchmark-comparison-table" aria-label="Permalink to &quot;Benchmark Comparison Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benchmark</th><th>Focus</th><th>Tasks</th><th>Languages</th><th>Tests Agentic Loop?</th><th>Key Metric</th><th>Cost per Run</th></tr></thead><tbody><tr><td>SWE-bench Verified</td><td>GitHub issue resolution</td><td>500</td><td>Python</td><td>Full loop</td><td>% Resolved</td><td>$1,000–2,500</td></tr><tr><td>SWE-bench Multilingual</td><td>Cross-language issues</td><td>300</td><td>9 languages</td><td>Full loop</td><td>% Resolved</td><td>$600–1,500</td></tr><tr><td>SWE-bench Multimodal</td><td>Visual issues</td><td>517</td><td>Python</td><td>Full loop</td><td>% Resolved</td><td>$1,000–2,500</td></tr><tr><td>Terminal-Bench 2.0</td><td>CLI tasks</td><td>89</td><td>Shell</td><td>Terminal agents</td><td>% Success</td><td>$50–200</td></tr><tr><td>HumanEval</td><td>Function completion</td><td>164</td><td>Python</td><td>Model only</td><td>pass@k</td><td>$1–10</td></tr><tr><td>MBPP</td><td>Basic programming</td><td>974</td><td>Python</td><td>Model only</td><td>pass@k</td><td>$5–50</td></tr><tr><td>AgentBench</td><td>Multi-environment</td><td>8 envs</td><td>Various</td><td>Partial</td><td>Composite</td><td>$200–500</td></tr><tr><td>CodeClash</td><td>Goal-oriented dev</td><td>TBD</td><td>Various</td><td>Full loop</td><td>TBD</td><td>TBD</td></tr><tr><td>Aider Bench</td><td>Code editing</td><td>133</td><td>Python</td><td>Edit loop</td><td>% Correct</td><td>$5–50</td></tr><tr><td>SWE-smith</td><td>Training data gen</td><td>N/A</td><td>Python</td><td>N/A (training)</td><td>Model quality</td><td>GPU hours</td></tr></tbody></table><hr><h2 id="the-benchmark-gap" tabindex="-1">The Benchmark Gap <a class="header-anchor" href="#the-benchmark-gap" aria-label="Permalink to &quot;The Benchmark Gap&quot;">​</a></h2><h3 id="what-benchmarks-miss" tabindex="-1">What Benchmarks Miss <a class="header-anchor" href="#what-benchmarks-miss" aria-label="Permalink to &quot;What Benchmarks Miss&quot;">​</a></h3><p>Current benchmarks evaluate a narrow slice of real-world agent usage:</p><p><strong>Long-running tasks.</strong> Real development tasks take hours or days, not the 2–10 minutes that benchmark tasks typically require. No benchmark tests whether an agent can maintain coherence over a multi-hour session, manage growing context, or resume after interruption.</p><p><strong>Multi-session work.</strong> Developers pick up where they left off. They context-switch between tasks. They come back the next day and continue. No benchmark tests session persistence, task handoff, or progressive understanding of a codebase over time.</p><p><strong>Real-world ambiguity.</strong> SWE-bench tasks are derived from actual GitHub issues, but they have been filtered and curated. The messiest real-world scenarios — contradictory requirements, underspecified behavior, missing documentation — are underrepresented.</p><p><strong>User interaction quality.</strong> How well does the agent communicate its progress? Does it ask clarifying questions at the right time? Does it explain its changes? These soft skills matter enormously in practice but are not measured by any current benchmark.</p><p><strong>Cost efficiency.</strong> Most benchmarks report only accuracy. In production, cost per task matters. An agent that scores 70 % at $0.50 per task may be more valuable than one that scores 75 % at $5.00 per task. Only Aider&#39;s benchmark systematically tracks cost.</p><p><strong>Safety.</strong> Does the agent execute dangerous commands? Does it overwrite files it should not? Does it leak secrets? These concerns are paramount in production but absent from benchmarks.</p><h3 id="goodhart-s-law-in-practice" tabindex="-1">Goodhart&#39;s Law in Practice <a class="header-anchor" href="#goodhart-s-law-in-practice" aria-label="Permalink to &quot;Goodhart&#39;s Law in Practice&quot;">​</a></h3><p>&quot;When a measure becomes a target, it ceases to be a good measure.&quot;</p><p>Several Goodhart&#39;s Law dynamics are visible in the coding-agent benchmark landscape:</p><ol><li><p><strong>Training data contamination</strong>: SWE-bench tasks are drawn from public GitHub repos. Models trained on internet data may have seen the exact solutions. SWE-bench Verified attempts to mitigate this with human vetting, but the concern persists.</p></li><li><p><strong>Benchmark-specific optimization</strong>: agents can be tuned for SWE-bench patterns (Django issues have certain characteristics, Scikit-learn issues have others) in ways that do not generalize to other repos or languages.</p></li><li><p><strong>Metric gaming</strong>: maximizing % Resolved on a fixed set of 500 tasks can lead to overfitting — an agent that handles those 500 patterns well but fails on the 501st.</p></li><li><p><strong>Leaderboard culture</strong>: the race to top the SWE-bench leaderboard can incentivize benchmark-specific tricks over genuine capability improvements.</p></li></ol><p>The antidote is <strong>multi-benchmark evaluation</strong>: test on SWE-bench <em>and</em> Terminal-Bench <em>and</em> Aider&#39;s benchmark <em>and</em> internal real-world tasks. An agent that scores well across all four is genuinely capable; one that tops SWE-bench but fails elsewhere has likely overfit.</p><hr><h2 id="best-practices-for-evaluation" tabindex="-1">Best Practices for Evaluation <a class="header-anchor" href="#best-practices-for-evaluation" aria-label="Permalink to &quot;Best Practices for Evaluation&quot;">​</a></h2><ol><li><p><strong>Use multiple benchmarks.</strong> SWE-bench alone is insufficient. Combine it with Terminal-Bench, Aider&#39;s benchmark, and ideally your own internal task set drawn from your actual codebase and workflows.</p></li><li><p><strong>Track cost per task, not just accuracy.</strong> Report both % Resolved and $/task. An agent that costs 10x more for 5 % higher accuracy may not be the right choice for production.</p></li><li><p><strong>Measure latency and user experience.</strong> Time-to-first-token, total task duration, and the number of user interactions required all matter. A benchmark that ignores these produces agents optimized for accuracy at the expense of usability.</p></li><li><p><strong>Test on real tasks, not just benchmarks.</strong> Maintain an internal eval set of tasks from your own repos. These tasks will have the ambiguity, scale, and context that public benchmarks lack.</p></li><li><p><strong>Compare against simple baselines.</strong> Always benchmark against the simplest possible agent (mini-SWE-agent style). If your complex loop does not meaningfully beat the simple one, the complexity is not paying for itself.</p></li><li><p><strong>Version your benchmark results.</strong> Models improve. Benchmarks evolve. Record the exact model version, benchmark version, date, and cost for every evaluation run. Without this metadata, historical comparisons are meaningless.</p></li><li><p><strong>Separate model quality from loop quality.</strong> Run HumanEval/MBPP alongside SWE-bench. If a model scores high on HumanEval but low on SWE-bench, the bottleneck is the loop. If both are low, improve the model first.</p></li><li><p><strong>Evaluate failure modes, not just success rates.</strong> A 70 % score means 30 % failure. Categorize those failures: wrong file? correct file but bad edit? good edit but test timeout? Each failure category points to a different loop improvement.</p></li></ol><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>Jimenez, C. E., et al. &quot;SWE-bench: Can Language Models Resolve Real-World GitHub Issues?&quot; (2023)</li><li>Liu, X., et al. &quot;AgentBench: Evaluating LLMs as Agents&quot; (2023)</li><li>Chen, M., et al. &quot;Evaluating Large Language Models Trained on Code&quot; (HumanEval, 2021)</li><li>Austin, J., et al. &quot;Program Synthesis with Large Language Models&quot; (MBPP, 2021)</li><li>Aider code editing benchmark: <a href="https://aider.chat/docs/leaderboards/" target="_blank" rel="noreferrer">https://aider.chat/docs/leaderboards/</a></li><li>SWE-bench leaderboard: <a href="https://www.swebench.com" target="_blank" rel="noreferrer">https://www.swebench.com</a></li><li>SWE-smith: <a href="https://swesmith.com" target="_blank" rel="noreferrer">https://swesmith.com</a></li><li>CodeClash: <a href="https://codeclash.ai" target="_blank" rel="noreferrer">https://codeclash.ai</a></li><li>Terminal-Bench: <a href="https://terminalbench.com" target="_blank" rel="noreferrer">https://terminalbench.com</a></li><li>mini-SWE-agent analysis: Princeton NLP blog</li></ul>`,151)])])}const u=t(o,[["render",i]]);export{g as __pageData,u as default};
